  `company_id` int(10) UNSIGNED DEFAULT NULL,
  `name` varchar(255) NOT NULL COMMENT 'Template name (e.g., Solar Installation, Electrical Check)',
  `description` text DEFAULT NULL COMMENT 'Template description',
  `items` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT 'Array of checklist items: [{text: string, order: number}]' CHECK (json_valid(`items`)),
