INSERT INTO `site_inspection_checklist_templates` (`id`, `company_id`, `name`, `description`, `items`, `is_active`, `created_at`, `updated_at`) VALUES
(1, NULL, 'Solar Installation', 'Standard checklist for solar panel installation inspections', '[{\"text\": \"Verify roof condition and integrity\", \"order\": 1}, {\"text\": \"Check safety harness connection points\", \"order\": 2}, {\"text\": \"Inspect electrical panel accessibility\", \"order\": 3}, {\"text\": \"Verify cable routing and conduit\", \"order\": 4}, {\"text\": \"Test emergency shut-off procedures\", \"order\": 5}, {\"text\": \"Confirm proper earthing/grounding\", \"order\": 6}, {\"text\": \"Check inverter mounting and ventilation\", \"order\": 7}, {\"text\": \"Verify all warning labels installed\", \"order\": 8}]', 1, '2026-03-22 22:56:26', NULL),
(2, NULL, 'Electrical Check', 'Comprehensive electrical system inspection', '[{\"text\":\"Test main switchboard functionalityuit\",\"order\":1},{\"text\":\"Verify circuit breaker operation\",\"order\":2},{\"text\":\"Check RCD/GFCI protection\",\"order\":3},{\"text\":\"Measure voltage at key points\",\"order\":4},{\"text\":\"Inspect cable insulation\",\"order\":5},{\"text\":\"Test earth continuity\",\"order\":6},{\"text\":\"Verify proper labeling of circuits\",\"order\":7}]', 1, '2026-03-22 22:56:26', '2026-03-22 23:10:54'),
(3, NULL, 'Roof Assessment', 'Detailed roof condition and safety check', '[{\"text\":\"Inspect roof material condition\",\"order\":1},{\"text\":\"Check for loose tiles or covering damage\",\"order\":2},{\"text\":\"Verify roof pitch measurement\",\"order\":3},{\"text\":\"Assess structural integrity\",\"order\":4},{\"text\":\"Check for water damage or leaks\",\"order\":5},{\"text\":\"Identify shading obstacles\",\"order\":6},{\"text\":\"Verify anchor points for safety equipment\",\"order\":7},{\"text\":\"Document roof access method\",\"order\":8},{\"text\":\"test\",\"order\":9},{\"text\":\"ếtt\",\"order\":10},{\"text\":\"test\",\"order\":11},{\"text\":\"test\",\"order\":12}]', 1, '2026-03-22 22:56:26', '2026-03-22 23:04:27'),
(4, NULL, 'Safety Compliance', 'General safety and compliance verification', '[{\"text\": \"Verify all safety signage in place\", \"order\": 1}, {\"text\": \"Check for asbestos risk areas\", \"order\": 2}, {\"text\": \"Confirm adequate lighting conditions\", \"order\": 3}, {\"text\": \"Inspect for tripping hazards\", \"order\": 4}, {\"text\": \"Verify emergency equipment accessible\", \"order\": 5}, {\"text\": \"Check ventilation adequacy\", \"order\": 6}, {\"text\": \"Confirm proper PPE requirements\", \"order\": 7}]', 1, '2026-03-22 22:56:26', NULL),
(6, NULL, 'test', NULL, '[{\"text\":\"test\",\"order\":1}]', 1, '2026-03-22 23:15:50', NULL);

